import React, { useState } from 'react';
import { SidebarSection } from '../types';
import { IconChevronDown, IconChevronRight, IconDot } from '../constants';

interface SidebarProps {
  data: SidebarSection[];
  currentItem: string;
  onSelectField: (item: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ data, currentItem, onSelectField }) => {
  // Initialize with the first group expanded
  const [expandedGroups, setExpandedGroups] = useState<Record<string, boolean>>({
    "Thông tin về trẻ": true
  });

  const toggleGroup = (groupName: string) => {
    setExpandedGroups(prev => ({
      ...prev,
      [groupName]: !prev[groupName]
    }));
  };

  const getStatusColor = (status: string | null) => {
    if (!status) return 'hidden';
    if (status === 'Hoàn thành') return 'text-green-700 bg-green-100 border-green-200';
    return 'text-red-700 bg-red-50 border-red-200';
  };

  return (
    <div className="flex flex-col h-full overflow-y-auto custom-scrollbar p-3 space-y-6">
      {data.map((section, idx) => (
        <div key={idx}>
          {/* Section Title */}
          <div className="flex items-center gap-2 mb-3 pb-2 border-b-2 border-slate-200">
            <div className="w-1.5 h-4 bg-blue-600 rounded-full shadow-sm"></div>
            <h3 className="text-xs font-extrabold text-slate-800 uppercase tracking-widest">
              {section.title}
            </h3>
          </div>

          <div className="space-y-3">
            {section.groups.map((group) => (
              <div key={group.name} className="border border-slate-200 rounded-lg overflow-hidden bg-white shadow-sm hover:shadow-md transition-all duration-200">
                {/* Group Header */}
                <div
                  onClick={() => toggleGroup(group.name)}
                  className={`flex items-center justify-between px-3 py-2.5 cursor-pointer select-none transition-colors ${
                    expandedGroups[group.name]
                      ? 'bg-slate-50 border-b border-slate-100'
                      : 'bg-white hover:bg-slate-50'
                  }`}
                >
                  <div className="flex-1 pr-2">
                    <div className={`font-bold text-sm ${expandedGroups[group.name] ? 'text-blue-800' : 'text-slate-700'}`}>
                      {group.name}
                    </div>
                    {group.status && (
                      <div className={`inline-flex items-center gap-1 px-1.5 py-0.5 mt-1 rounded text-[10px] font-semibold border ${getStatusColor(group.status)}`}>
                        {group.status}
                      </div>
                    )}
                  </div>
                  <div className={`${expandedGroups[group.name] ? 'text-blue-600' : 'text-slate-400'}`}>
                    {expandedGroups[group.name] ? <IconChevronDown /> : <IconChevronRight />}
                  </div>
                </div>

                {/* Group Items */}
                {expandedGroups[group.name] && (
                  <div className="bg-white">
                    {group.items.map((item) => (
                      <button
                        key={item}
                        onClick={() => onSelectField(item)}
                        className={`w-full text-left px-3 py-2.5 text-sm flex items-center gap-2.5 transition-all border-l-[3px] border-b border-slate-50 last:border-b-0 ${
                          currentItem === item
                            ? 'bg-blue-50/80 border-l-blue-600 text-blue-900 font-bold'
                            : 'border-l-transparent text-slate-600 hover:bg-slate-50 hover:text-slate-900 hover:border-l-slate-300'
                        }`}
                      >
                        <IconDot className={`shrink-0 ${currentItem === item ? 'text-blue-600' : 'text-slate-300'}`} />
                        {item}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import Sidebar from './Sidebar';
import { SIDEBAR_DATA, INITIAL_STUDENTS, IconSave, IconTrash2, IconCopy, IconCheckSquare, IconSquare, IconAlertCircle, IconX, IconChevronDown, IconDot } from '../constants';
import { Student } from '../types';

interface BatchInputModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const BatchInputModal: React.FC<BatchInputModalProps> = ({ isOpen, onClose }) => {
  // -- STATE DỮ LIỆU --
  const [students, setStudents] = useState<Student[]>(INITIAL_STUDENTS);
  const [currentItem, setCurrentItem] = useState("Con thứ mấy");

  // Dropdown states
  const [showApplyMenu, setShowApplyMenu] = useState(false);
  const [showClearMenu, setShowClearMenu] = useState(false);

  // Click outside handler for dropdowns
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (!(event.target as HTMLElement).closest('button.dropdown-trigger')) {
        setShowApplyMenu(false);
        setShowClearMenu(false);
      }
    };
    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  // -- LOGIC --
  const handleSelectField = (itemName: string) => {
    setCurrentItem(itemName);
    // Reset selections and simulate loading data for new field
    setStudents(prev => prev.map(s => ({...s, value: '', isSelected: false})));
  };

  const handleInputChange = (id: string, newValue: string) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...s, value: newValue } : s));
  };

  const toggleSelect = (id: string) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...s, isSelected: !s.isSelected } : s));
  };

  const toggleSelectAll = () => {
    const allSelected = students.every(s => s.isSelected);
    setStudents(prev => prev.map(s => ({ ...s, isSelected: !allSelected })));
  };

  const applyData = (type: 'all' | 'selected') => {
    const sourceValue = students[0].value;
    if (!sourceValue) {
      alert(`Vui lòng nhập giá trị mẫu cho học sinh đầu tiên (Bùi Vạn Thảo Tiên) ở mục "${currentItem}" trước khi áp dụng!`);
      return;
    }
    setStudents(prev => prev.map((s, index) => {
      if (index === 0) return s; 
      if (type === 'all') return { ...s, value: sourceValue };
      else return s.isSelected ? { ...s, value: sourceValue } : s;
    }));
    setShowApplyMenu(false);
  };

  const clearData = (type: 'all' | 'selected') => {
    if(!confirm("Bạn có chắc chắn muốn xóa dữ liệu này không?")) return;
    setStudents(prev => prev.map(s => {
      if (type === 'all') return { ...s, value: '' };
      else return s.isSelected ? { ...s, value: '' } : s;
    }));
    setShowClearMenu(false);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* Overlay */}
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" onClick={onClose}></div>

      {/* Modal Content */}
      <div className="relative w-full max-w-[95vw] h-[90vh] bg-white rounded-xl shadow-2xl flex flex-col overflow-hidden animate-in fade-in zoom-in-95 duration-200">

        {/* --- MODAL HEADER --- */}
        <div className="h-16 px-6 border-b border-slate-200 flex items-center justify-between bg-white shrink-0 z-20">
            <div className="flex items-center gap-4">
                <div className="bg-blue-100 p-2 rounded-lg text-blue-600">
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><polyline points="10 9 9 9 8 9"></polyline></svg>
                </div>
                <div>
                    <h2 className="text-lg font-bold text-slate-900">Nhập liệu sức khỏe</h2>
                    <p className="text-xs text-slate-500 font-medium">Lớp Mầm 1 • Năm học 2024-2025</p>
                </div>
            </div>

            <button 
                onClick={onClose}
                className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
                title="Đóng (Esc)"
            >
                <IconX size={24} />
            </button>
        </div>

        {/* --- MODAL BODY (2 COLUMNS) --- */}
        <div className="flex flex-1 overflow-hidden">

            {/* LEFT SIDEBAR */}
            <div className="w-[300px] bg-slate-50 border-r border-slate-200 flex flex-col h-full shrink-0">
                <Sidebar 
                    data={SIDEBAR_DATA} 
                    currentItem={currentItem} 
                    onSelectField={handleSelectField} 
                />
            </div>

            {/* RIGHT CONTENT */}
            <div className="flex-1 flex flex-col h-full min-w-0 bg-white relative">

                {/* TOOLBAR */}
                <div className="h-14 px-6 border-b border-slate-200 flex items-center justify-between bg-white shrink-0 z-10 shadow-[0_2px_4px_rgba(0,0,0,0.02)]">
                    <div className="flex items-center gap-2">
                        <span className="text-slate-500 font-medium text-sm">Đang nhập:</span>
                        <h1 className="text-base font-bold text-blue-700 bg-blue-50 px-3 py-1 rounded-md border border-blue-100">
                            {currentItem}
                        </h1>
                    </div>

                    <div className="flex items-center gap-2">
                        {/* Nút XÓA (Dropdown) */}
                        <div className="relative">
                            <button 
                                onClick={(e) => {e.stopPropagation(); setShowClearMenu(!showClearMenu); setShowApplyMenu(false);}}
                                className="dropdown-trigger flex items-center gap-2 px-3 py-1.5 bg-white text-slate-600 hover:text-red-600 hover:bg-red-50 hover:border-red-200 rounded-md text-sm font-semibold transition-all border border-slate-300 shadow-sm"
                            >
                                <IconTrash2 size={16} />
                                <span>Xóa</span>
                                <IconChevronDown size={14} className="opacity-50" />
                            </button>

                            {showClearMenu && (
                                <div className="absolute right-0 mt-2 w-64 bg-white rounded-lg shadow-xl border border-slate-200 py-1 z-30 animate-in fade-in zoom-in-95 duration-100">
                                    <button onClick={() => clearData('selected')} className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-3">
                                        <IconCheckSquare size={16} className="text-slate-400"/> 
                                        <span>Xóa dòng đang chọn</span>
                                    </button>
                                    <div className="border-t border-slate-100 my-1"></div>
                                    <button onClick={() => clearData('all')} className="w-full text-left px-4 py-3 text-sm text-red-600 hover:bg-red-50 flex items-center gap-3 font-medium">
                                        <IconTrash2 size={16} /> 
                                        <span>Xóa tất cả dữ liệu</span>
                                    </button>
                                </div>
                            )}
                        </div>

                        {/* Nút ĐIỀN NHANH (Dropdown) */}
                        <div className="relative">
                            <button 
                                onClick={(e) => {e.stopPropagation(); setShowApplyMenu(!showApplyMenu); setShowClearMenu(false);}}
                                className="dropdown-trigger flex items-center gap-2 px-3 py-1.5 bg-orange-50 text-orange-800 hover:bg-orange-100 hover:border-orange-300 rounded-md text-sm font-bold transition-all border border-orange-200 shadow-sm"
                            >
                                <IconCopy size={16} />
                                <span>Sao chép mẫu</span>
                                <IconChevronDown size={14} className="opacity-50" />
                            </button>

                            {showApplyMenu && (
                                <div className="absolute right-0 mt-2 w-80 bg-white rounded-lg shadow-xl border border-slate-200 py-1 z-30 overflow-hidden animate-in fade-in zoom-in-95 duration-100">
                                    <div className="px-4 py-2.5 bg-orange-50 border-b border-orange-100">
                                        <div className="text-[10px] text-orange-600 uppercase font-bold mb-1 tracking-wider">Nguồn dữ liệu (Dòng 1)</div>
                                        <div className="text-sm font-bold text-orange-900 truncate flex items-center gap-1.5">
                                            <span className="bg-orange-200 text-orange-800 text-[10px] px-1.5 py-0.5 rounded border border-orange-300">Mẫu</span>
                                            {students[0].name}
                                        </div>
                                    </div>
                                    <button onClick={() => applyData('selected')} className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-3 transition-colors">
                                        <div className="p-1.5 bg-slate-100 rounded text-slate-500"><IconCheckSquare size={16} /></div>
                                        <div>
                                            <div className="font-semibold text-slate-800">Áp dụng cho dòng chọn</div>
                                            <div className="text-xs text-slate-500">Chỉ điền vào các ô đã tick</div>
                                        </div>
                                    </button>
                                    <button onClick={() => applyData('all')} className="w-full text-left px-4 py-3 text-sm text-orange-800 hover:bg-orange-50 flex items-center gap-3 border-t border-slate-100 transition-colors">
                                        <div className="p-1.5 bg-orange-100 rounded text-orange-600"><IconCopy size={16} /></div>
                                        <div>
                                            <div className="font-bold">Áp dụng cho cả lớp</div>
                                            <div className="text-xs text-orange-600/70">Điền vào tất cả các dòng</div>
                                        </div>
                                    </button>
                                </div>
                            )}
                        </div>

                        <div className="w-px h-8 bg-slate-200 mx-2"></div>

                        {/* Nút LƯU */}
                        <button 
                            onClick={onClose}
                            className="flex items-center gap-2 px-5 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg text-sm font-bold shadow-md hover:shadow-lg hover:-translate-y-0.5 transition-all active:scale-95 border border-blue-700"
                        >
                            <IconSave size={18} />
                            LƯU
                        </button>
                    </div>
                </div>

                {/* TABLE AREA */}
                <div className="flex-1 overflow-auto bg-slate-100 p-6">
                    <div className="bg-white rounded-lg shadow-sm border border-slate-300 overflow-hidden mx-auto max-w-5xl">
                        <table className="w-full text-left border-collapse">
                            <thead className="sticky top-0 z-10 shadow-sm">
                                <tr className="bg-slate-100 text-xs uppercase text-slate-600 font-bold border-b border-slate-300">
                                    <th className="py-3 px-4 w-12 text-center border-r border-slate-200 bg-slate-100">
                                        <button onClick={toggleSelectAll} className="flex items-center justify-center w-full hover:scale-110 transition-transform active:scale-95" title="Chọn tất cả">
                                            {students.every(s => s.isSelected) 
                                                ? <IconCheckSquare className="text-blue-600" size={20} /> 
                                                : <IconSquare className="text-slate-400" size={20} />}
                                        </button>
                                    </th>
                                    <th className="py-3 px-4 w-14 text-center border-r border-slate-200 bg-slate-100">STT</th>
                                    <th className="py-3 px-4 w-32 border-r border-slate-200 bg-slate-100">Mã HS</th>
                                    <th className="py-3 px-4 w-64 border-r border-slate-200 bg-slate-100">Họ và tên</th>
                                    <th className="py-3 px-4 text-blue-800 bg-blue-50 border-l border-blue-100 shadow-[inset_0_2px_4px_rgba(0,0,0,0.05)]">
                                        Giá trị nhập <span className="font-normal text-blue-600 ml-1">({currentItem})</span>
                                    </th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-200">
                                {/* DÒNG 1: DÒNG MẪU (MASTER ROW) */}
                                {students.length > 0 && (
                                    <tr className="bg-orange-50 hover:bg-orange-100 transition-colors relative group border-b-2 border-orange-200">
                                        <td className="py-3 px-4 text-center border-r border-orange-200/50">
                                           <div className="flex justify-center">
                                                <IconDot className="text-orange-400"/>
                                           </div>
                                        </td>
                                        <td className="py-3 px-4 text-center text-sm font-bold text-orange-700 border-r border-orange-200/50">1</td>
                                        <td className="py-3 px-4 text-sm font-mono text-orange-800/80 border-r border-orange-200/50">{students[0].code}</td>
                                        <td className="py-3 px-4 border-r border-orange-200/50">
                                            <div className="flex items-center gap-2">
                                                <span className="text-sm font-bold text-orange-900">{students[0].name}</span>
                                                <span className="text-[10px] font-extrabold px-1.5 py-0.5 rounded bg-orange-500 text-white uppercase shadow-sm tracking-wide">
                                                    Mẫu
                                                </span>
                                            </div>
                                            <div className="text-[10px] text-orange-600 mt-0.5 font-medium">Nhập vào đây để sao chép xuống dưới</div>
                                        </td>
                                        <td className="py-3 px-4 bg-orange-50/50">
                                            <input 
                                                type="text" 
                                                value={students[0].value}
                                                onChange={(e) => handleInputChange(students[0].id, e.target.value)}
                                                placeholder="Nhập giá trị mẫu..."
                                                className="w-full px-3 py-2.5 text-sm rounded-md border-2 border-orange-300 bg-white focus:border-orange-500 focus:ring-4 focus:ring-orange-200 text-slate-900 placeholder-orange-300 font-bold transition-all shadow-sm"
                                                autoFocus
                                            />
                                        </td>
                                    </tr>
                                )}

                                {/* CÁC DÒNG CÒN LẠI */}
                                {students.slice(1).map((student, index) => (
                                    <tr 
                                        key={student.id} 
                                        className="hover:bg-blue-50 transition-colors group bg-white"
                                    >
                                        <td className="py-3 px-4 text-center border-r border-slate-100">
                                            <button onClick={() => toggleSelect(student.id)} className="text-slate-300 hover:text-blue-600 transition-colors active:scale-95">
                                                {student.isSelected ? <IconCheckSquare className="text-blue-600" size={20} /> : <IconSquare size={20} />}
                                            </button>
                                        </td>
                                        <td className="py-3 px-4 text-center text-sm text-slate-500 font-mono border-r border-slate-100">
                                            {index + 2}
                                        </td>
                                        <td className="py-3 px-4 text-sm text-slate-500 font-mono border-r border-slate-100">
                                            {student.code}
                                        </td>
                                        <td className="py-3 px-4 border-r border-slate-100 text-slate-700 text-sm font-medium">
                                            {student.name}
                                        </td>
                                        <td className="py-2 px-4 bg-slate-50/30 group-hover:bg-blue-50/30 transition-colors">
                                            <input 
                                                type="text" 
                                                value={student.value}
                                                onChange={(e) => handleInputChange(student.id, e.target.value)}
                                                placeholder="Nhập..."
                                                className="w-full px-3 py-2 text-sm rounded border border-slate-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 text-slate-800 transition-all placeholder-slate-300"
                                            />
                                            {/* Validation Warning Example */}
                                            {student.value && currentItem === "Tổng số con trong gia đình" && isNaN(Number(student.value)) && (
                                                <div className="text-[11px] text-red-600 mt-1 flex items-center gap-1 font-semibold animate-pulse">
                                                    <IconAlertCircle /> Vui lòng nhập số
                                                </div>
                                            )}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>

                        <div className="bg-slate-50 px-6 py-3 text-center border-t border-slate-200">
                            <span className="text-xs text-slate-400 font-semibold uppercase tracking-wider">-- Hết danh sách ({students.length} học sinh) --</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default BatchInputModal;

import React from 'react';
import { SidebarSection } from '../types';

interface SidebarProps {
  data: SidebarSection[];
  currentItem: string;
  onSelectField: (item: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ data, currentItem, onSelectField }) => {
  // Helper for badge colors
  const getStatusColor = (status: string | null) => {
    if (!status) return 'hidden';
    if (status === 'Hoàn thành') return 'text-green-700 bg-green-100 border-green-200';
    return 'text-red-700 bg-red-50 border-red-200';
  };

  return (
    <div className="flex flex-col h-full overflow-y-auto custom-scrollbar py-4">
      {data.map((section, idx) => (
        <div key={idx} className="mb-6 last:mb-0">
            {/* Section Heading */}
            <div className="px-4 mb-3 flex items-center gap-3">
                 <div className="h-px bg-slate-200 flex-1"></div>
                 <h3 className="text-[11px] font-extrabold text-slate-400 uppercase tracking-widest whitespace-nowrap">
                    {section.title}
                 </h3>
                 <div className="h-px bg-slate-200 flex-1"></div>
            </div>

            <div className="px-3 space-y-5">
                {section.groups.map((group) => (
                    <div key={group.name}>
                        {/* Group Title */}
                        <div className="px-3 mb-2 flex items-center justify-between">
                            <span className="text-sm font-extrabold text-slate-900 uppercase tracking-tight">{group.name}</span>
                            {group.status && (
                                <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded border ${getStatusColor(group.status)}`}>
                                    {group.status}
                                </span>
                            )}
                        </div>

                        {/* List Items */}
                        <div className="flex flex-col gap-1">
                            {group.items.map((item) => {
                                const isActive = currentItem === item;
                                return (
                                    <button
                                        key={item}
                                        onClick={() => onSelectField(item)}
                                        className={`group relative w-full text-left px-3 py-2.5 text-sm rounded-lg transition-all duration-200 flex items-center gap-3
                                            ${isActive 
                                                ? 'bg-white text-blue-700 shadow-[0_1px_3px_rgba(0,0,0,0.1)] ring-1 ring-slate-200/50 z-10' 
                                                : 'text-slate-600 hover:bg-slate-200/50 hover:text-slate-900'
                                            }`}
                                    >
                                        <div className={`w-1.5 h-1.5 rounded-full shrink-0 transition-colors duration-200 ${isActive ? 'bg-blue-600 scale-125' : 'bg-slate-300 group-hover:bg-slate-400'}`}></div>
                                        <span className={`truncate ${isActive ? 'font-bold' : 'font-semibold'}`}>{item}</span>

                                        {/* Active Indicator Bar */}
                                        {isActive && (
                                            <div className="absolute left-0 top-1/2 -translate-y-1/2 w-[3px] h-5 bg-blue-600 rounded-r-full"></div>
                                        )}
                                    </button>
                                );
                            })}
                        </div>
                    </div>
                ))}
            </div>
        </div>
      ))}

      {/* Footer / Padding at bottom */}
      <div className="h-8"></div>
    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { SidebarSection } from '../types';
import { IconChevronRight } from '../constants';

interface SidebarProps {
  data: SidebarSection[];
  currentItem: string;
  onSelectField: (item: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ data, currentItem, onSelectField }) => {
  // Trạng thái đóng/mở của các nhóm. Mặc định mở một vài nhóm quan trọng.
  const [expandedGroups, setExpandedGroups] = useState<Record<string, boolean>>({
    "Thông tin về trẻ": true,
    "Theo dõi sức khỏe": true
  });

  const toggleGroup = (groupName: string) => {
    setExpandedGroups(prev => ({
      ...prev,
      [groupName]: !prev[groupName]
    }));
  };

  const getStatusColor = (status: string | null) => {
    if (!status) return 'hidden';
    if (status === 'Hoàn thành') return 'text-green-700 bg-green-100 border-green-200';
    return 'text-red-700 bg-red-50 border-red-200';
  };

  return (
    <div className="flex flex-col h-full overflow-y-auto custom-scrollbar py-6 px-4 bg-slate-50/50">
      {data.map((section, idx) => (
        <div key={idx} className="mb-8 last:mb-0">
            {/* 
               SECTION HEADING 
               Thiết kế nổi bật: Chữ đậm, màu tối, có border bên trái 
            */}
            <div className="mb-4 pl-3 border-l-4 border-blue-700">
                 <h3 className="text-sm font-black text-slate-800 uppercase tracking-wider leading-tight">
                    {section.title}
                 </h3>
            </div>

            <div className="space-y-3">
                {section.groups.map((group) => {
                    const isExpanded = expandedGroups[group.name];
                    const hasActiveChild = group.items.includes(currentItem);

                    return (
                    <div 
                        key={group.name} 
                        className={`rounded-lg transition-all duration-200 border bg-white shadow-sm overflow-hidden
                            ${hasActiveChild ? 'border-blue-300 ring-1 ring-blue-100' : 'border-slate-200'}
                        `}
                    >
                        {/* Group Header (Dropdown Trigger) */}
                        <button
                            onClick={() => toggleGroup(group.name)}
                            className={`w-full flex items-center justify-between px-3 py-3 text-left transition-colors select-none
                                ${isExpanded ? 'bg-slate-50 border-b border-slate-100' : 'hover:bg-slate-50'}
                            `}
                        >
                            <div className="flex items-center gap-3 overflow-hidden">
                                <div className={`text-slate-400 transition-transform duration-200 shrink-0 ${isExpanded ? 'rotate-90 text-blue-600' : ''}`}>
                                    <IconChevronRight size={16} />
                                </div>
                                <span className={`text-sm font-bold truncate ${hasActiveChild ? 'text-blue-800' : 'text-slate-700'}`}>
                                    {group.name}
                                </span>
                            </div>

                            {group.status && (
                                <span className={`text-[10px] font-bold px-2 py-0.5 rounded border shrink-0 ml-2 ${getStatusColor(group.status)}`}>
                                    {group.status}
                                </span>
                            )}
                        </button>

                        {/* Dropdown Content Items */}
                        {isExpanded && (
                            <div className="bg-white py-2">
                                <div className="flex flex-col">
                                    {group.items.map((item) => {
                                        const isActive = currentItem === item;
                                        return (
                                            <button
                                                key={item}
                                                onClick={() => onSelectField(item)}
                                                className={`relative w-full text-left px-4 py-2 text-[13px] transition-all duration-150 flex items-center gap-3
                                                    ${isActive 
                                                        ? 'bg-blue-600 text-white font-bold shadow-md mx-2 w-auto rounded-md' 
                                                        : 'text-slate-600 hover:bg-slate-100 hover:text-slate-900 font-medium pl-10'
                                                    }`}
                                            >
                                                {/* Dấu chấm trang trí cho các mục chưa chọn */}
                                                {!isActive && (
                                                    <div className="w-1 h-1 rounded-full bg-slate-300 shrink-0"></div>
                                                )}

                                                <span className="truncate">{item}</span>
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        )}
                    </div>
                )})}
            </div>
        </div>
      ))}
      <div className="h-8"></div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import Sidebar from './Sidebar';
import { SIDEBAR_DATA, INITIAL_STUDENTS, IconSave, IconTrash2, IconCopy, IconCheckSquare, IconSquare, IconAlertCircle, IconX, IconChevronDown, IconDot } from '../constants';
import { Student } from '../types';

interface BatchInputModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const BatchInputModal: React.FC<BatchInputModalProps> = ({ isOpen, onClose }) => {
  // -- STATE DỮ LIỆU --
  const [students, setStudents] = useState<Student[]>(INITIAL_STUDENTS);
  const [currentItem, setCurrentItem] = useState("Con thứ mấy");

  // Dropdown states
  const [showApplyMenu, setShowApplyMenu] = useState(false);
  const [showClearMenu, setShowClearMenu] = useState(false);

  // Click outside handler for dropdowns
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (!(event.target as HTMLElement).closest('button.dropdown-trigger')) {
        setShowApplyMenu(false);
        setShowClearMenu(false);
      }
    };
    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  // -- LOGIC --
  const handleSelectField = (itemName: string) => {
    setCurrentItem(itemName);
    // Reset selections and simulate loading data for new field
    setStudents(prev => prev.map(s => ({...s, value: '', isSelected: false})));
  };

  const handleInputChange = (id: string, newValue: string) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...s, value: newValue } : s));
  };

  const toggleSelect = (id: string) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...s, isSelected: !s.isSelected } : s));
  };

  const toggleSelectAll = () => {
    const allSelected = students.every(s => s.isSelected);
    setStudents(prev => prev.map(s => ({ ...s, isSelected: !allSelected })));
  };

  const applyData = (type: 'all' | 'selected') => {
    const sourceValue = students[0].value;
    if (!sourceValue) {
      alert(`Vui lòng nhập giá trị mẫu cho học sinh đầu tiên (Bùi Vạn Thảo Tiên) ở mục "${currentItem}" trước khi áp dụng!`);
      return;
    }
    setStudents(prev => prev.map((s, index) => {
      if (index === 0) return s; 
      if (type === 'all') return { ...s, value: sourceValue };
      else return s.isSelected ? { ...s, value: sourceValue } : s;
    }));
    setShowApplyMenu(false);
  };

  const clearData = (type: 'all' | 'selected') => {
    if(!confirm("Bạn có chắc chắn muốn xóa dữ liệu này không?")) return;
    setStudents(prev => prev.map(s => {
      if (type === 'all') return { ...s, value: '' };
      else return s.isSelected ? { ...s, value: '' } : s;
    }));
    setShowClearMenu(false);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* Overlay */}
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" onClick={onClose}></div>

      {/* Modal Content */}
      <div className="relative w-full max-w-[95vw] h-[90vh] bg-white rounded-xl shadow-2xl flex flex-col overflow-hidden animate-in fade-in zoom-in-95 duration-200">

        {/* --- MODAL HEADER --- */}
        <div className="h-16 px-6 border-b border-slate-200 flex items-center justify-between bg-white shrink-0 z-20">
            <div className="flex items-center gap-4">
                <div className="bg-blue-100 p-2 rounded-lg text-blue-600">
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><polyline points="10 9 9 9 8 9"></polyline></svg>
                </div>
                <div>
                    <h2 className="text-lg font-bold text-slate-900">Nhập liệu sức khỏe</h2>
                    <p className="text-xs text-slate-500 font-medium">Lớp Mầm 1 • Năm học 2024-2025</p>
                </div>
            </div>

            <button 
                onClick={onClose}
                className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
                title="Đóng (Esc)"
            >
                <IconX size={24} />
            </button>
        </div>

        {/* --- MODAL BODY (2 COLUMNS) --- */}
        <div className="flex flex-1 overflow-hidden">

            {/* LEFT SIDEBAR */}
            <div className="w-[300px] bg-slate-50 border-r border-slate-200 flex flex-col h-full shrink-0">
                <Sidebar 
                    data={SIDEBAR_DATA} 
                    currentItem={currentItem} 
                    onSelectField={handleSelectField} 
                />
            </div>

            {/* RIGHT CONTENT */}
            <div className="flex-1 flex flex-col h-full min-w-0 bg-white relative">

                {/* TOOLBAR */}
                <div className="h-14 px-6 border-b border-slate-200 flex items-center justify-between bg-white shrink-0 z-10 shadow-[0_2px_4px_rgba(0,0,0,0.02)]">
                    <div className="flex items-center gap-2">
                        <span className="text-slate-500 font-medium text-sm">Đang nhập:</span>
                        <h1 className="text-base font-bold text-blue-700 bg-blue-50 px-3 py-1 rounded-md border border-blue-100">
                            {currentItem}
                        </h1>
                    </div>

                    <div className="flex items-center gap-2">
                        {/* Nút XÓA (Dropdown) */}
                        <div className="relative">
                            <button 
                                onClick={(e) => {e.stopPropagation(); setShowClearMenu(!showClearMenu); setShowApplyMenu(false);}}
                                className="dropdown-trigger flex items-center gap-2 px-3 py-1.5 bg-white text-slate-600 hover:text-red-600 hover:bg-red-50 hover:border-red-200 rounded-md text-sm font-semibold transition-all border border-slate-300 shadow-sm"
                            >
                                <IconTrash2 size={16} />
                                <span>Xóa</span>
                                <IconChevronDown size={14} className="opacity-50" />
                            </button>

                            {showClearMenu && (
                                <div className="absolute right-0 mt-2 w-64 bg-white rounded-lg shadow-xl border border-slate-200 py-1 z-30 animate-in fade-in zoom-in-95 duration-100">
                                    <button onClick={() => clearData('selected')} className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-3">
                                        <IconCheckSquare size={16} className="text-slate-400"/> 
                                        <span>Xóa dòng đang chọn</span>
                                    </button>
                                    <div className="border-t border-slate-100 my-1"></div>
                                    <button onClick={() => clearData('all')} className="w-full text-left px-4 py-3 text-sm text-red-600 hover:bg-red-50 flex items-center gap-3 font-medium">
                                        <IconTrash2 size={16} /> 
                                        <span>Xóa tất cả dữ liệu</span>
                                    </button>
                                </div>
                            )}
                        </div>

                        {/* Nút ĐIỀN NHANH (Dropdown) */}
                        <div className="relative">
                            <button 
                                onClick={(e) => {e.stopPropagation(); setShowApplyMenu(!showApplyMenu); setShowClearMenu(false);}}
                                className="dropdown-trigger flex items-center gap-2 px-3 py-1.5 bg-orange-50 text-orange-800 hover:bg-orange-100 hover:border-orange-300 rounded-md text-sm font-bold transition-all border border-orange-200 shadow-sm"
                            >
                                <IconCopy size={16} />
                                <span>Sao chép mẫu</span>
                                <IconChevronDown size={14} className="opacity-50" />
                            </button>

                            {showApplyMenu && (
                                <div className="absolute right-0 mt-2 w-80 bg-white rounded-lg shadow-xl border border-slate-200 py-1 z-30 overflow-hidden animate-in fade-in zoom-in-95 duration-100">
                                    <div className="px-4 py-2.5 bg-orange-50 border-b border-orange-100">
                                        <div className="text-[10px] text-orange-600 uppercase font-bold mb-1 tracking-wider">Nguồn dữ liệu (Dòng 1)</div>
                                        <div className="text-sm font-bold text-orange-900 truncate flex items-center gap-1.5">
                                            <span className="bg-orange-200 text-orange-800 text-[10px] px-1.5 py-0.5 rounded border border-orange-300">Mẫu</span>
                                            {students[0].name}
                                        </div>
                                    </div>
                                    <button onClick={() => applyData('selected')} className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-3 transition-colors">
                                        <div className="p-1.5 bg-slate-100 rounded text-slate-500"><IconCheckSquare size={16} /></div>
                                        <div>
                                            <div className="font-semibold text-slate-800">Áp dụng cho dòng chọn</div>
                                            <div className="text-xs text-slate-500">Chỉ điền vào các ô đã tick</div>
                                        </div>
                                    </button>
                                    <button onClick={() => applyData('all')} className="w-full text-left px-4 py-3 text-sm text-orange-800 hover:bg-orange-50 flex items-center gap-3 border-t border-slate-100 transition-colors">
                                        <div className="p-1.5 bg-orange-100 rounded text-orange-600"><IconCopy size={16} /></div>
                                        <div>
                                            <div className="font-bold">Áp dụng cho cả lớp</div>
                                            <div className="text-xs text-orange-600/70">Điền vào tất cả các dòng</div>
                                        </div>
                                    </button>
                                </div>
                            )}
                        </div>

                        <div className="w-px h-8 bg-slate-200 mx-2"></div>

                        {/* Nút LƯU */}
                        <button 
                            onClick={onClose}
                            className="flex items-center gap-2 px-5 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg text-sm font-bold shadow-md hover:shadow-lg hover:-translate-y-0.5 transition-all active:scale-95 border border-blue-700"
                        >
                            <IconSave size={18} />
                            LƯU
                        </button>
                    </div>
                </div>

                {/* TABLE AREA */}
                <div className="flex-1 overflow-auto bg-white">
                    <div className="w-full">
                        <table className="w-full text-left border-collapse table-fixed">
                            <thead className="sticky top-0 z-10 shadow-sm bg-white">
                                <tr className="text-xs uppercase text-slate-600 font-bold border-b border-slate-300">
                                    <th className="py-3 px-4 w-12 text-center border-r border-slate-200 bg-slate-50">
                                        <button onClick={toggleSelectAll} className="flex items-center justify-center w-full hover:scale-110 transition-transform active:scale-95" title="Chọn tất cả">
                                            {students.every(s => s.isSelected) 
                                                ? <IconCheckSquare className="text-blue-600" size={20} /> 
                                                : <IconSquare className="text-slate-400" size={20} />}
                                        </button>
                                    </th>
                                    <th className="py-3 px-4 w-14 text-center border-r border-slate-200 bg-slate-50">STT</th>
                                    <th className="py-3 px-4 w-[15%] min-w-[120px] border-r border-slate-200 bg-slate-50">Mã HS</th>
                                    <th className="py-3 px-4 w-[25%] min-w-[200px] border-r border-slate-200 bg-slate-50">Họ và tên</th>
